import (
	"fmt"
	"net/http"
	"sync"
	"time"
)

func main() {
	// Configurable URL
	url := "https://example.com"

	// Number of concurrent goroutines
	numGoroutines := 5

	// Create a channel to collect results
	resultsChan := make(chan struct{}, numGoroutines)

	// Create a sync.Mutex for thread safety
	mutex := &sync.Mutex{}

	// Function to send HTTP GET request and collect results
	sendRequest := func(i int) {
		// Start a new goroutine
		go func() {
			// Send HTTP GET request
			resp, err := http.Get(url)
			if err != nil {
				// Log error
				mutex.Lock()
				defer mutex.Unlock()
				fmt.Printf("Error sending request %d: %v\n", i, err)
				return
			}
			// Check if response is successful
			if resp.StatusCode != http.StatusOK {
				// Log error
				mutex.Lock()
				defer mutex.Unlock()
				fmt.Printf("Request %d failed with status %d\n", i, resp.StatusCode)
				return
			}
			// Log success
			mutex.Lock()
			defer mutex.Unlock()
			fmt.Printf("Request %d succeeded\n", i)
			// Add to results channel
			resultsChan <- struct{}{}
		}()
	}

	// Start all goroutines
	for i := 0; i < numGoroutines; i++ {
		sendRequest(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < numGoroutines; i++ {
		<-resultsChan
	}

	// Log total successful responses
	mutex.Lock()
	defer mutex.Unlock()
	fmt.Printf("Total successful responses: %d\n", len(resultsChan))
}

